86: def tryStreamsArchetype() {
87:   try {
88:     doStreamsArchetype()
89:   } catch(err) {
90:     echo 'Failed to build Kafka Streams archetype, marking this build UNSTABLE'
91:     currentBuild.result = 'UNSTABLE'
92:   }
93: }
